script:
exports.main = function (config, context) {
    config.addScriptLine( "snmp" );
    config.addScriptLine( "mode enable" );
    config.addScriptLine( "user " + context.vars.SNMP_USER + " AuthPriv SHA " + context.vars.SNMP_AUTH_PW + " AES "+context.vars.SNMP_PRIV_PW+"" );
    config.addScriptLine( "group " + context.vars.SNMP_USER + " usm "+context.vars.SNMP_Group+"" );
    config.addScriptLine( "view super included .1" );
    config.addScriptLine( "access "+context.vars.SNMP_Group+" any AuthPriv super super" );
    config.addScriptLine( "exit" );
};
